unitsize(2 cm);

pair A, B, C;

A = dir(20);
B = dir(20 + 120);
C = dir(20 + 240);

//draw((-1.5,0)--(1.5,0));
//draw((0,-1.5)--(0,1.5));
draw(Circle((0,0),1));
draw((0,0)--A,Arrow(6));
draw((0,0)--B,Arrow(6));
draw((0,0)--C,Arrow(6));
draw(A--B--C--cycle,dashed);

label("$\mathbf{a}$", A, A);
label("$\mathbf{b}$", B, B);
label("$\mathbf{c}$", C, C);
[/asy]

